import React, { useState } from "react";
import "./App.css";

function defaultPlayers() {
  return [
    { id: 1, name: "Alice", cash: 150, zchut: 0, properties: [] },
    { id: 2, name: "Bob", cash: 150, zchut: 0, properties: [] },
    { id: 3, name: "Carol", cash: 150, zchut: 0, properties: [] },
  ];
}

function defaultProperties() {
  return [
    { id: "p1", name: "Mediterranean Ave", value: 60, ownerId: 1 },
    { id: "p2", name: "Baltic Ave", value: 60, ownerId: null },
    { id: "p3", name: "Oriental Ave", value: 100, ownerId: null },
  ];
}

export default function App() {
  const [players, setPlayers] = useState(defaultPlayers());
  const [properties, setProperties] = useState(defaultProperties());

  // rescue modal state
  const [rescue, setRescue] = useState({
    open: false,
    needyId: null,
    amountDue: 0,
    context: null, // optional: { type: 'rent', payerId, ownerId, amount }
  });

  // helper to update player
  function updatePlayer(updated) {
    setPlayers((p) => p.map((pl) => (pl.id === updated.id ? updated : pl)));
  }

  // attempt to pay rent: if insufficient, open rescue modal
  function payRent(payerId, ownerId, amount) {
    const payer = players.find((p) => p.id === payerId);
    const owner = players.find((p) => p.id === ownerId);
    if (!payer || !owner) return;

    if (payer.cash >= amount) {
      payer.cash -= amount;
      owner.cash += amount;
      updatePlayer(payer);
      updatePlayer(owner);
      return { success: true };
    }

    // cannot pay -> open rescue modal
    const shortfall = amount - payer.cash;
    setRescue({
      open: true,
      needyId: payerId,
      amountDue: shortfall,
      context: { type: "rent", payerId, ownerId, amount },
    });
    return { success: false };
  }

  function closeRescueModal() {
    setRescue({ open: false, needyId: null, amountDue: 0, context: null });
  }

  // give money from another player to needy player; awardsZchut true -> giver gains zchut
  function giveMoney(fromPlayerId, amount, awardsZchut = true) {
    const giver = players.find((p) => p.id === fromPlayerId);
    const needy = players.find((p) => p.id === rescue.needyId);
    if (!giver || !needy) return;
    const give = Math.min(amount, giver.cash);
    if (give <= 0) return;

    giver.cash -= give;
    needy.cash += give;
    if (awardsZchut) giver.zchut = (giver.zchut || 0) + 1;

    updatePlayer(giver);
    updatePlayer(needy);

    // if needy can now cover their debt, complete the pending action
    if (needy.cash >= (rescue.amountDue || 0)) {
      finalizePendingPayment();
      closeRescueModal();
    } else {
      // update remaining shortfall
      setRescue((r) => ({ ...r, amountDue: Math.max(0, (r.amountDue || 0) - give) }));
    }
  }

  // buy a property from the needy player
  function buyProperty(buyerId, propertyId, price) {
    const buyer = players.find((p) => p.id === buyerId);
    const needy = players.find((p) => p.id === rescue.needyId);
    if (!buyer || !needy) return;
    if (buyer.cash < price) return;

    // transfer property
    const prop = properties.find((pr) => pr.id === propertyId && pr.ownerId === needy.id);
    if (!prop) return;

    // update property owner
    setProperties((ps) => ps.map((pr) => (pr.id === prop.id ? { ...pr, ownerId: buyer.id } : pr)));

    buyer.cash -= price;
    needy.cash += price;
    updatePlayer(buyer);
    updatePlayer(needy);

    // re-evaluate shortfall
    if (needy.cash >= (rescue.amountDue || 0)) {
      finalizePendingPayment();
      closeRescueModal();
    } else {
      setRescue((r) => ({ ...r, amountDue: Math.max(0, (r.amountDue || 0) - price) }));
    }
  }

  // finalize the original pending payment (e.g., rent) once needy has funds
  function finalizePendingPayment() {
    const ctx = rescue.context;
    if (!ctx) return;
    if (ctx.type === "rent") {
      const payer = players.find((p) => p.id === ctx.payerId);
      const owner = players.find((p) => p.id === ctx.ownerId);
      if (!payer || !owner) return;
      const amount = ctx.amount;
      // deduct what's possible (payer now should have enough)
      const payAmount = Math.min(payer.cash, amount);
      payer.cash -= payAmount;
      owner.cash += payAmount;
      updatePlayer(payer);
      updatePlayer(owner);
    }
    // future contexts can be handled here
  }

  // UI helpers for demo/testing
  function triggerRentFailDemo() {
    // try to charge player 2 (Bob) rent of 300 from player 1 (Alice) -> triggers rescue
    payRent(2, 1, 300);
  }

  function renderPlayer(p) {
    const owned = properties.filter((pr) => pr.ownerId === p.id);
    return (
      <div key={p.id} className="player-card">
        <strong>{p.name}</strong>
        <div>Cash: {p.cash}</div>
        <div>Zchut: {p.zchut || 0}</div>
        <div>
          Properties:
          <ul>
            {owned.map((pr) => (
              <li key={pr.id}>
                {pr.name} (value {pr.value})
              </li>
            ))}
            {owned.length === 0 && <li>—</li>}
          </ul>
        </div>
      </div>
    );
  }

  function RescueModal() {
    if (!rescue.open) return null;
    const needy = players.find((p) => p.id === rescue.needyId) || {};
    const others = players.filter((p) => p.id !== rescue.needyId);
    const needyProps = properties.filter((pr) => pr.ownerId === rescue.needyId);

    return (
      <div className="rescue-overlay" style={overlayStyle}>
        <div className="rescue-card" style={cardStyle}>
          <h3>Rescue / Zchut - {needy.name || "Player"}</h3>
          <p>Amount still needed: {rescue.amountDue}</p>
          <p>Needy cash: {needy.cash}</p>

          <div>
            <h4>Other players — give money</h4>
            {others.map((op) => (
              <div key={op.id} style={{ marginBottom: 8 }}>
                <span>
                  {op.name} (cash: {op.cash}){" "}
                </span>
                <button onClick={() => giveMoney(op.id, rescue.amountDue, true)}>Give Needed (award Zchut)</button>{" "}
                <button onClick={() => giveMoney(op.id, 10, false)}>Give 10 (no Zchut)</button>
              </div>
            ))}
          </div>

          <div>
            <h4>Buy property from {needy.name}</h4>
            {needyProps.length === 0 && <div>Nothing to sell</div>}
            {needyProps.map((pr) => {
              const suggested = Math.max(1, Math.floor(pr.value * 0.75));
              return (
                <div key={pr.id} style={{ marginBottom: 8 }}>
                  <span>
                    {pr.name} (value {pr.value}) — suggested price {suggested}
                  </span>
                  {others.map((op) => (
                    <button key={op.id + pr.id} onClick={() => buyProperty(op.id, pr.id, suggested)}>
                      {op.name} buy
                    </button>
                  ))}
                </div>
              );
            })}
          </div>

          <div style={{ marginTop: 12 }}>
            <button onClick={closeRescueModal}>Close</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="app-root" style={{ padding: 16 }}>
      <h2>Monopoly (minimal) — App.js replacement</h2>
      <div style={{ display: "flex", gap: 12 }}>{players.map(renderPlayer)}</div>

      <div style={{ marginTop: 16 }}>
        <button onClick={triggerRentFailDemo}>Demo: Trigger Rent Failure (Bob owes Alice 300)</button>
      </div>

      <div style={{ marginTop: 16 }}>
        <h4>Properties (global)</h4>
        <ul>
          {properties.map((pr) => (
            <li key={pr.id}>
              {pr.name} — value {pr.value} — owner:{" "}
              {players.find((p) => p.id === pr.ownerId)?.name || "Bank"}
            </li>
          ))}
        </ul>
      </div>

      <RescueModal />
    </div>
  );
}

// simple inline styles to avoid extra files
const overlayStyle = {
  position: "fixed",
  left: 0,
  top: 0,
  right: 0,
  bottom: 0,
  background: "rgba(0,0,0,0.5)",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  zIndex: 9999,
};
const cardStyle = {
  background: "#fff",
  padding: 16,
  borderRadius: 6,
  minWidth: 420,
};
